module binary_counter(reset, enable, count);  

    input  reset;  
    input  enable;  
    output  [1:0] count;  
    reg   [1:0]  count; 
    initial count = 0;

    always @(posedge reset)
          begin
            if (enable)
                count <= count + 1;
          end  

endmodule
